  assert a == CountVal(doors, 0); assert b == CountVal(doors, 1);

  var x := 0;
  var y := 0;
  i := 0;
  while i < n
    invariant 0 <= i <= n
    invariant x == CountVal(doors[..i], 0)
    invariant y == CountVal(doors[..i], 1)
    invariant forall j | 0 <= j <= i :: !CanExitAfter(doors, j)
  {
    assert doors[i] == 0 || doors[i] == 1;
    assert x == CountVal(doors[..i], 0); assert y == CountVal(doors[..i], 1);
    if doors[i] == 1 {
      y := y + 1;
    } else {
      x := x + 1;
    }
    if x == a || y == b {
      return i + 1;
    }
    assert !CanExitAfter(doors, i + 1);
    i := i + 1;
  }
  assert doors[..n] == doors;
  assert 1 <= n; assert CanExitAfter(doors, n);
  return 0;
}
